```javascript
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  if (trailing === false && leading === false) {
    throw new Error('至少开启 leading 或 trailing 之一');
  }

  let timer = null;
  let lastInvokeTime = 0;
  let lastArgs = null;
  let maxTimer = null;

  function invoke(time) {
    lastInvokeTime = time;
    fn.apply(this, lastArgs);
    lastArgs = null;
    if (maxTimer) {
      clearTimeout(maxTimer);
      maxTimer = null;
    }
  }

  function startTimer(time, remainingWait) {
    timer = setTimeout(() => {
      timer = null;
      if (trailing && lastArgs) {
        invoke(time);
      }
      if (maxTimer) {
        clearTimeout(maxTimer);
        maxTimer = null;
      }
    }, remainingWait);
  }

  function debounced(...args) {
    const time = Date.now();
    const elapsed = time - lastInvokeTime;

    lastArgs = args;

    // 首次调用时 lastInvokeTime = 0，elapsed 会很大
    const isFirstCall = lastInvokeTime === 0;

    if (leading && isFirstCall) {
      invoke(time);
      return;
    }

    // leading 模式下，距离上次调用已超过 delay，立即执行
    if (leading && elapsed >= delay) {
      invoke(time);
      return;
    }

    // 清除已有的 trailing 定时器
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // maxWait 保障：即使持续触发，也至少每 maxWait 执行一次
    if (maxWait && maxWait > delay && !maxTimer) {
      maxTimer = setTimeout(() => {
        maxTimer = null;
        if (lastArgs) {
          invoke(Date.now());
        }
      }, maxWait - elapsed);
    }

    if (trailing) {
      startTimer(time, delay);
    }
  }

  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    if (maxTimer) {
      clearTimeout(maxTimer);
      maxTimer = null;
    }
    lastArgs = null;
    lastInvokeTime = 0;
  };

  debounced.flush = function () {
    if (timer && lastArgs) {
      clearTimeout(timer);
      timer = null;
      invoke(Date.now());
    }
    if (maxTimer) {
      clearTimeout(maxTimer);
      maxTimer = null;
    }
  };

  return debounced;
}
```

几个要点快速过一下：

**核心机制** — 每次触发重置定时器，只有停止触发超过 `delay` ms 后才执行。就像电梯门：不断有人进来就不断重置关门计时。

**leading / trailing** — `leading` 控制是否在第一次触发时立即执行（响应用户第一下操作），`trailing` 控制是否在停止触发后执行最后一次。默认 `trailing: true, leading: false`，和 Lodash 一致。

**maxWait** — 保证即使一直被触发，也最多等 `maxWait` ms 就必须执行一次。典型场景：页面 resize，用户一直拖着窗口不放，没有 `maxWait` 的话回调永远不会执行。

**cancel / flush** — 分别用来取消等待中的调用或立即触发最后一次等待中的调用，组件卸载时很有用。

用法：
```javascript
const log = debounce(console.log, 300);
log('a'); log('b'); log('c');
// 停止 300ms 后只输出 'c'
```

```javascript
const save = debounce(saveToServer, 500, { leading: true, maxWait: 2000 });
// 第一次立即保存，后续每 2s 至少保一次
```

