// 定义一个判别字段（discriminant），这里用 kind
type Shape =
  | { kind: "circle"; radius: number }
  | { kind: "square"; side: number }
  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle"; base: number; height: number };

// TypeScript 能根据 kind 值自动收窄类型
function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      // 这里 shape 被收窄为 { kind: "circle"; radius: number }
      return Math.PI * shape.radius ** 2;
    case "square":
      // 收窄为 { kind: "square"; side: number }
      return shape.side ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return (shape.base * shape.height) / 2;
  }
}

// 如果你加了一个新的变体但忘了处理，可以借助 never 做 exhaustiveness check
function assertNever(x: never): never {
  throw new Error("Unexpected variant: " + x);
}

function areaSafe(shape: Shape): number {
  switch (shape.kind) {
    case "circle": return Math.PI * shape.radius ** 2;
    case "square": return shape.side ** 2;
    case "rectangle": return shape.width * shape.height;
    case "triangle": return (shape.base * shape.height) / 2;
    default: return assertNever(shape); // 如果有未处理的变体，编译报错
  }
}

console.log(area({ kind: "circle", radius: 5 }));    // 78.54...
console.log(area({ kind: "square", side: 4 }));      // 16
console.log(area({ kind: "rectangle", width: 3, height: 7 })); // 21
```

核心要点就三个：

1. **一个公共字段做"标签"** —— 上面用的是 `kind`，值必须是字符串字面量（`"circle"`、`"square"` 等）
2. **每个变体可以带不同的数据结构** —— `circle` 只有 `radius`，`rectangle` 有 `width` 和 `height`，`triangle` 又是另一组字段
3. **TypeScript 自动收窄类型** —— 在 `switch`（或 `if`）分支里，编译器知道当前分支对应哪个变体，不需要手动类型断言

搭配 `never` 的 exhaustiveness check 是锦上添花：如果你后续往 `Shape` 加了 `"pentagon"` 但忘了补 `area` 的处理，编译直接报错，不会留运行时漏洞。

